$ErrorActionPreference="Stop";$root=Split-Path -Parent $PSScriptRoot;$godot=Get-ChildItem -LiteralPath (Join-Path $root ".tools\Godot") -Recurse -Filter "Godot*_mono_win64_console.exe"|Select-Object -First 1;if(-not $godot){throw "Portable Godot console executable was not found."};for($run=1;$run -le 10;$run++){$ErrorActionPreference="Continue";$output=& $godot.FullName --headless --fixed-fps 60 --path $root "res://scenes/Room25.tscn" --quit-after 1900 -- --room25-solution-smoke 2>&1;$exitCode=$LASTEXITCODE;$ErrorActionPreference="Stop";$output|Write-Output;if($exitCode -ne 0){throw "Room 25 solution smoke test run $run exited with code $exitCode"};if(($output-join"`n")-notmatch"ROOM25_SOLUTION_PASS: SolutionTrace steered four surface stages, accelerated to (?!0\.00)([0-9]+\.[0-9]+) m/s, shattered at (?!0\.00)([0-9]+\.[0-9]+) m/s, slowed on sticky from (?!0\.00)([0-9]+\.[0-9]+) to (?!0\.00)([0-9]+\.[0-9]+) m/s and bounced at (?!0\.00)([0-9]+\.[0-9]+) m/s onto the exit deck"){throw "Room 25 run $run did not prove the full surface relay."}};Write-Output "ROOM25_SOLUTION_BATCH_PASS: 10 clean-process completions proved the four-stage surface relay."
